changeSet.sql:
WITH DuplicateGroups AS ( SELECT "paymentReference", "paymentPeriod", "paymentAmount", "transactionDate", COUNT(*) AS duplicate_count FROM public.d365 GROUP BY "paymentReference", "paymentPeriod", "paymentAmount", "transactionDate" HAVING COUNT(*) > 1 ),
MaxDatePublished AS ( SELECT d."paymentReference", d."paymentPeriod", d."paymentAmount", d."transactionDate", MAX(d."datePublished") AS max_date_published FROM public.d365 d INNER JOIN DuplicateGroups dg ON d."paymentReference" = dg."paymentReference" AND d."paymentPeriod" = dg."paymentPeriod" AND d."paymentAmount" = dg."paymentAmount" AND d."transactionDate" = dg."transactionDate" GROUP BY d."paymentReference", d."paymentPeriod", d."paymentAmount", d."transactionDate" )
DELETE FROM public.d365 d USING MaxDatePublished mdp WHERE d."paymentReference" = mdp."paymentReference" AND d."paymentPeriod" = mdp."paymentPeriod" AND d."paymentAmount" = mdp."paymentAmount" AND d."transactionDate" = mdp."transactionDate" AND d."datePublished" = mdp.max_date_published;
